def apply(state, ctx):
    votes = ctx['interactions']['votes']
    tax = 0
    gift = 0
    for picks in votes.values():
        for oid in picks:
            if oid == 'tax':
                tax += 1
            elif oid == 'gift':
                gift += 1
    order = state.turn_order
    leader = order[0]
    for pid in order:
        if state.player(pid).score > state.player(leader).score:
            leader = pid
    if tax >= gift:
        state.subtract_points('id:' + leader, 5)
    else:
        state.add_points('id:' + leader, 5)
